function _syncPatients(): void { _setPatientsState?.([...mockPatients]); }

const generatePatientId = (): string => {
  const numericIds = mockPatients.map(p => parseInt(p.id)).filter(n => Number.isInteger(n) && n >= 100001 && n <= 999999);
  return String(numericIds.length ? Math.max(...numericIds) + 1 : 100001);
};


