// ─── CUSTOM DEPARTMENT SUB-ITEMS CATALOG (used only when adding/editing a custom department) ──
// Labels are generated dynamically from the department's own name — no hardcoded department names.
const CUSTOM_DEPT_SUBITEM_ORDER: Array<{ id: string; labelFor: (name: string) => string }> = [
  { id: "open-patient", labelFor: () => "فتح ملف مريض / تسجيل مريض" },
  { id: "lab-session", labelFor: (n) => `جلسات وطلبات ${n} وتعبئة النتائج` },
  { id: "test-catalog", labelFor: (n) => `دليل أسعار خدمات ${n}` },
  { id: "surgery-clinic-inv", labelFor: (n) => `مستلزمات ${n}` },
  { id: "lab-queue", labelFor: () => "قوائم الحالات" },
  { id: "queue", labelFor: () => "قائمة الانتظار" },
  { id: "purchase-reqs", labelFor: () => "طلبات الشراء" },
  { id: "print-export", labelFor: () => "الطباعة والتصدير" },
  { id: "attendance", labelFor: () => "دوام الموظفين" },
  { id: "vouchers", labelFor: () => "السندات وحساباتها" },
  { id: "dept-profit", labelFor: () => "الربح" },
  { id: "dept-debts", labelFor: () => "الديون" },
  { id: "dept-revenue", labelFor: () => "الإيرادات / الدخل" },
  { id: "dept-expenses", labelFor: () => "المصروفات" },
];
const getCustomDeptSubItem = (id: string, deptName: string): PermSubItem | undefined => {
  const base = AVAILABLE_DEPT_SUBITEMS[id];
  const order = CUSTOM_DEPT_SUBITEM_ORDER.find(o => o.id === id);
  if (!base || !order) return undefined;
  return { ...base, label: order.labelFor(deptName || "القسم") };
};
const getCustomDeptSubItemCatalog = (deptName: string): PermSubItem[] =>
  CUSTOM_DEPT_SUBITEM_ORDER.map(o => getCustomDeptSubItem(o.id, deptName)).filter(Boolean) as PermSubItem[];

const getDeptSubItems = (deptId: string, customDepts: Array<{ id: string; name?: string; subItemIds?: string[] }>): PermSubItem[] => {
  if (DEPT_PERM_TREE[deptId]) return DEPT_PERM_TREE[deptId];
  const cd = customDepts.find(d => d.id === deptId);
  if (cd?.subItemIds?.length) return cd.subItemIds.map(id => getCustomDeptSubItem(id, cd.name || "")).filter(Boolean) as PermSubItem[];
  return DEPT_PERM_TREE["surgery"] || [];
};

