  const doWithdraw = async (dept: string, amount: number, title: string, cat?: string, ben?: string, allowNegative: boolean = false): Promise<number | null> => {
    const currentBal = drawersRef.current[dept]?.balance ?? 0;
    if (!drawersRef.current[dept] || (!allowNegative && currentBal < amount)) return null;
    const _dt = _nowDT();
    const txId = Date.now();
    setDrawers(d => { if (!d[dept] || (!allowNegative && d[dept].balance < amount)) return d; const bal = d[dept].balance - amount; const tx: DrawerTx = { id: txId, type: "out", title, category: cat || "", beneficiary: ben, amount, balance: bal, time: _dt.time, date: _dt.date }; return { ...d, [dept]: { balance: bal, txs: [tx, ...(d[dept]?.txs ?? [])] } }; });
    // Server ledger computes the authoritative balance; no client balance sent.
    try {
      const r: any = await api.drawers.transactions.create({ dept, type: "out", title, category: cat || "", beneficiary: ben, amount, tx_date: api.parseDateISO(_dt.date), tx_time: _dt.time });
      if (!r || r.id == null) {
        setDrawers(d => { if (!d[dept]) return d; const bal = d[dept].balance + amount; return { ...d, [dept]: { balance: bal, txs: (d[dept].txs || []).filter(t => t.id !== txId) } }; });
        toast(`⚠️ فشل حفظ حركة السحب "${title}" بالخادم — الرصيد لم يتغيّر فعلياً، تحقق من الاتصال أو الجلسة وحاول مجدداً`, "error");
        return null;
      }
      return r.id;
    } catch {
      setDrawers(d => { if (!d[dept]) return d; const bal = d[dept].balance + amount; return { ...d, [dept]: { balance: bal, txs: (d[dept].txs || []).filter(t => t.id !== txId) } }; });
      toast(`⚠️ فشل حفظ حركة السحب "${title}" بالخادم — الرصيد لم يتغيّر فعلياً، تحقق من الاتصال أو الجلسة وحاول مجدداً`, "error");
      return null;
    }
  };
  const doDeposit = async (dept: string, amount: number, title: string, cat?: string): Promise<number | null> => {
    const _dt = _nowDT();
    const txId = Date.now();
    setDrawers(d => { const cur = d[dept]?.balance ?? 0; const bal = cur + amount; const tx: DrawerTx = { id: txId, type: "in", title, category: cat || "", amount, balance: bal, time: _dt.time, date: _dt.date, auto: false }; return { ...d, [dept]: { balance: bal, txs: [tx, ...(d[dept]?.txs ?? [])] } }; });
    // Server ledger computes the authoritative balance; no client balance sent.
    try {
      const r: any = await api.drawers.transactions.create({ dept, type: "in", title, category: cat || "", amount, tx_date: api.parseDateISO(_dt.date), tx_time: _dt.time, is_opening_balance: cat === "رصيد افتتاحي" });
      if (!r || r.id == null) {
        setDrawers(d => { if (!d[dept]) return d; const bal = d[dept].balance - amount; return { ...d, [dept]: { balance: bal, txs: (d[dept].txs || []).filter(t => t.id !== txId) } }; });
        toast(`⚠️ فشل حفظ حركة الإيداع "${title}" بالخادم — الرصيد لم يتغيّر فعلياً، تحقق من الاتصال أو الجلسة وحاول مجدداً`, "error");
        return null;
      }
      return r.id;
    } catch {
      setDrawers(d => { if (!d[dept]) return d; const bal = d[dept].balance - amount; return { ...d, [dept]: { balance: bal, txs: (d[dept].txs || []).filter(t => t.id !== txId) } }; });
      toast(`⚠️ فشل حفظ حركة الإيداع "${title}" بالخادم — الرصيد لم يتغيّر فعلياً، تحقق من الاتصال أو الجلسة وحاول مجدداً`, "error");
      return null;
    }
  };
  const doAdjustBalance = (dept: string, newBalance: number, reason: string) => {
    const cur = drawersRef.current[dept]?.balance ?? 0;
    const diff = newBalance - cur;
    const _dt = _nowDT();
    setDrawers(d => { const c = d[dept]?.balance ?? 0; const d2 = newBalance - c; const tx: DrawerTx = { id: Date.now(), type: d2 >= 0 ? "in" : "out", title: reason || "تعديل رصيد يدوي", category: "تعديل رصيد", amount: Math.abs(d2), balance: newBalance, time: _dt.time, date: _dt.date, auto: false }; return { ...d, [dept]: { ...d[dept], balance: newBalance, txs: [tx, ...(d[dept]?.txs ?? [])] } }; });
    // Server ledger computes the authoritative balance; no client balance sent.
    api.drawers.transactions.create({ dept, type: diff >= 0 ? "in" : "out", title: reason || "تعديل رصيد يدوي", category: "تعديل رصيد", amount: Math.abs(diff), tx_date: api.parseDateISO(_dt.date), tx_time: _dt.time });
  };
  const onAddDeptDrawer = (deptId: string) => {
    setDrawers(d => ({ ...d, [deptId]: { balance: 0, txs: [] } }));
    api.drawers.upsert(deptId, 0);
  };
  const initialPurchaseRequests: PurchaseRequest[] = [];
  const [purchaseRequests, setPurchaseRequests] = useState<PurchaseRequest[]>(initialPurchaseRequests);
  const _prDateISO = (dateStr: string) => { const raw = (dateStr || "").split(" — ")[0].trim(); return api.parseDateISO(raw) || _localISO(); };
  const onSubmitPurchaseRequest = (req: Omit<PurchaseRequest, "id" | "status">) => {
    const _prId = Date.now();
    setPurchaseRequests(p => [...p, { ...req, id: _prId, status: "pending" }]);
    // ── الأصناف لازم تُرسَل بأسماء حقول snake_case (estimated_price) لأن راوت
    //    الباك إند بيقرأها هيك — إرسالها بـ camelCase (estimatedPrice) كان
    //    بيخلي كل صنف يُحفَظ بسعر تقديري = صفر رغم إدخال المستخدم لسعر حقيقي ──
    const itemsForDb = (req.items || []).map(it => ({ name: it.name, qty: it.qty, unit: it.unit, estimated_price: it.estimatedPrice, note: it.note }));
    api.finance.purchaseRequests.create({ dept: req.dept, requested_by: req.requestedBy, date: _prDateISO(req.date), items: itemsForDb, total_amount: req.totalAmount, paid_amount: req.paidAmount || 0, note: req.note, supplier: req.supplier || null, supplier_id: req.supplierId ?? null }).then(r => { if (r && (r as any).id) setPurchaseRequests(p => p.map(x => x.id === _prId ? { ...x, id: (r as any).id } : x)); }).catch(() => { });
  };
  // ── لحظة الموافقة، المدير بيقدر يحدد: (1) خصم تحفيزي حصل عليه من الشركة
  //    المورّدة فينخصم من الإجمالي الكلي للطلب، و(2) قديه بده يسدد الآن فعلياً
  //    (كامل أو جزئي أو ولا شي حالياً) — بدل ما كان النظام قديماً يسحب تلقائياً
  //    كامل مبلغ الطلب من الصندوق فور الموافقة بغض النظر عن قرار المدير الفعلي.
  //    الدفعة المسددة الآن بتتسجل بنفس سجل الدفعات المستخدم لاحقاً بزر "تسديد" ──
  const onApprovePurchaseRequest = async (id: number, opts?: { discountAmount?: number; paidNow?: number }): Promise<boolean> => {
    const req = purchaseRequests.find(r => r.id === id); if (!req) return false;
    const discountAmount = Math.max(0, opts?.discountAmount || 0);
    const newTotal = Math.max(0, req.totalAmount - discountAmount);
    const paidNow = Math.min(Math.max(0, opts?.paidNow || 0), newTotal);
    try {
      await api.finance.purchaseRequests.update(id, { dept: req.dept, requested_by: req.requestedBy, date: _prDateISO(req.date), total_amount: newTotal, discount_amount: discountAmount, status: "approved", approved_by: "المدير", approved_date: _localISO(), note: req.note });
      setPurchaseRequests(p => p.map(r => r.id === id ? { ...r, status: "approved", approvedBy: "المدير", approvedDate: _today(), discountAmount, totalAmount: newTotal } : r));
      if (paidNow > 0) {
        const now = new Date();
        const dateTimeStr = `${_localISO()} ${now.toLocaleTimeString("ar-EG", { hour: "2-digit", minute: "2-digit" })}`;
        const remaining = Math.max(0, newTotal - paidNow);
        const note = `دفعة عند اعتماد الطلب بقيمة ${fmt(paidNow)} بتاريخ ${dateTimeStr} والباقي ${fmt(remaining)} لطلب الشراء #${id}`;
        // ── نحفظ رقم حركة السحب الحقيقي على الطلب نفسه (drawer_tx_id)، لنستطيع
        //    لاحقاً عند حذف الطلب أو تعديل مبلغه حذف/تصحيح هذه الحركة بالتحديد
        //    بدل تركها معلّقة للأبد في سجل الصندوق ──
        const txId = await doWithdraw(req.dept, paidNow, note, "مشتريات مُعتمدة");
        if (txId) {
          setPurchaseRequests(p => p.map(r => r.id === id ? { ...r, drawerTxId: txId } : r));
          api.finance.purchaseRequests.update(id, { drawer_tx_id: txId }).catch(() => { });
        }
        let voucherId: number | null = null;
        try {
          const rv = await api.finance.paymentVouchers.create({ date: _localISO(), amount: paidNow, paid_to_type: "supplier", paid_to_id: req.supplierId ?? null, paid_to_name: req.supplier || "مورد", reason: note, dept: req.dept, category: "مشتريات مُعتمدة", notes: note, drawer_tx_id: txId || null, settlement_breakdown: { purchaseRequest: { requestId: id, amount: paidNow } } as SettlementBreakdown });
          if (rv && (rv as any).id) { voucherId = (rv as any).id; setPaymentVouchersGlobal(p => [{ ...(rv as any), amount: Number((rv as any).amount) }, ...p]); }
        } catch { /* نكمل حتى لو فشل إنشاء سند الصرف */ }
        const r = await api.finance.purchaseRequests.payments.create(id, { amount: paidNow, note, drawer_tx_id: txId || null, payment_voucher_id: voucherId });
        const realId = r && (r as any).payment ? (r as any).payment.id : Date.now();
        setPurchaseRequests(p => p.map(x => x.id === id ? { ...x, paidAmount: (x.paidAmount || 0) + paidNow, payments: [...(x.payments || []), { id: realId, requestId: id, amount: paidNow, note, date: new Date().toISOString() }] } : x));
      }
      return true;
    } catch {
      toast("⚠️ تعذّرت الموافقة على الطلب — تحقق من الاتصال وحاول مرة أخرى", "error");
      return false;
    }
  };
  const onRejectPurchaseRequest = (id: number, reason: string) => {
    setPurchaseRequests(p => p.map(r => r.id === id ? { ...r, status: "rejected", rejectionReason: reason } : r));
    const req = purchaseRequests.find(r => r.id === id);
    if (req) api.finance.purchaseRequests.update(id, { dept: req.dept, requested_by: req.requestedBy, date: _prDateISO(req.date), total_amount: req.totalAmount, status: "rejected", rejection_reason: reason, note: req.note });
  };
  const onDeletePurchaseRequest = (id: number) => {
    const req = purchaseRequests.find(r => r.id === id);
    setPurchaseRequests(p => p.filter(r => r.id !== id));
    api.finance.purchaseRequests.delete(id).catch(() => { });
    // ── إذا كان الطلب مُعتمَداً وله حركة سحب مرتبطة فعلياً بالصندوق، نحذف تلك
    //    الحركة بالتحديد (حذف حقيقي معكوس عبر الـ ledger) بدل تركها معلّقة
    //    للأبد كـ"ملاحظة" في سجل المصروفات مع رصيد صندوق منقوص من غير رجعة ──
    if (req?.drawerTxId) api.drawers.transactions.delete(req.drawerTxId).catch(() => { });
  };
  // ── تعديل كامل لطلب شراء (المدير فقط) — يشمل الأصناف؛ يُقارن مع النسخة
  //    الأصلية لتحديد أي صنف يُحذف/يُحدَّث/يُضاف عبر الـ API بدل حذف وإعادة
  //    إنشاء الطلب كله ──
  const onEditPurchaseRequest = (id: number, updated: { dept: string; requestedBy: string; date: string; supplier: string; supplierId?: number; note: string; paidAmount: number; items: PurchaseItem[] }) => {
    const orig = purchaseRequests.find(r => r.id === id); if (!orig) return;
    const totalAmount = updated.items.reduce((s, it) => s + (it.qty || 0) * (it.estimatedPrice || 0), 0);
    // ── حماية إضافية: هذا المسار (تعديل عام لطلب شراء) ما لازم يُستخدم أبداً
    //    لتغيير المبلغ المدفوع الفعلي — أي تغيير حقيقي بالمدفوع لازم يمر حصراً
    //    عبر "تسديد" (onSettlePurchaseRequestPayment) اللي بيسحب فعلياً من
    //    الصندوق وينشئ سند صرف مرتبط. لو استُدعيت هذه الدالة بمبلغ مدفوع مختلف
    //    (من أي مصدر مستقبلي)، نتجاهله ونُبقي المبلغ الأصلي — لمنع تضخّم
    //    "المصروفات" بمعادلة الربح الموحّدة دون أي نقص حقيقي مقابل من الصندوق. ──
    const safePaidAmount = orig.paidAmount || 0;
    setPurchaseRequests(p => p.map(r => r.id === id ? { ...r, dept: updated.dept, requestedBy: updated.requestedBy, date: updated.date, supplier: updated.supplier, supplierId: updated.supplierId, note: updated.note, paidAmount: safePaidAmount, totalAmount, items: updated.items } : r));
    api.finance.purchaseRequests.update(id, { dept: updated.dept, requested_by: updated.requestedBy, date: _prDateISO(updated.date), total_amount: totalAmount, paid_amount: safePaidAmount, note: updated.note, supplier: updated.supplier || null, supplier_id: updated.supplierId ?? null }).catch(() => { });
    const origIds = new Set(orig.items.map(it => it.id));
    const keptIds = new Set(updated.items.map(it => it.id));
    orig.items.forEach(it => { if (!keptIds.has(it.id)) api.finance.purchaseRequests.items.delete(it.id).catch(() => { }); });
    updated.items.forEach(it => {
      if (origIds.has(it.id)) {
        api.finance.purchaseRequests.items.update(it.id, { name: it.name, qty: it.qty, unit: it.unit, estimated_price: it.estimatedPrice, note: it.note }).catch(() => { });
      } else {
        api.finance.purchaseRequests.items.create(id, { name: it.name, qty: it.qty, unit: it.unit, estimated_price: it.estimatedPrice, note: it.note }).catch(() => { });
      }
    });
  };
  // ── تسديد دفعة (كاملة أو جزئية) لطلب شراء مُعتمَد — يُنشئ سجل دفعة منفصل
  //    (بدل الكتابة فوق حقل paidAmount المفرد فقط)، مع ملاحظة تلقائية، وسحب
  //    حقيقي من صندوق القسم، وسند صرف حقيقي — بنفس مبدأ سندات القبض لتحصيل
  //    التأمين (كل دفعة حقيقية لازم تظهر بحسابات النظام الموحّدة). ──
  // ── ترجع Promise<boolean> (نجحت الدفعة فعلياً بالسيرفر أو لأ) بدل ما ترجع
  //    void بصمت — لأن الشاشة (confirmSettle) كانت عم تعرض توست "نجاح" فوراً
  //    بدون ما تنتظر نتيجة الاتصال الحقيقية، فلو فشل الاتصال (مثلاً مصادقة
  //    منتهية) المستخدم كان يشوف "تم" بينما ما انحفظ أي شي فعلياً بقاعدة البيانات ──
  const onSettlePurchaseRequestPayment = async (id: number, amount: number): Promise<boolean> => {
    const req = purchaseRequests.find(r => r.id === id); if (!req) return false;
    const remaining = Math.max(0, req.totalAmount - (req.paidAmount || 0));
    const amt = Math.min(Math.max(0, amount), remaining);
    if (amt <= 0) return false;
    const newRemaining = Math.max(0, remaining - amt);
    const now = new Date();
    const dateTimeStr = `${_localISO()} ${now.toLocaleTimeString("ar-EG", { hour: "2-digit", minute: "2-digit" })}`;
    const note = `تم سداد دفعة بقيمة ${fmt(amt)} بتاريخ ${dateTimeStr} والباقي ${fmt(newRemaining)} لطلب الشراء #${id}`;
    const tempId = Date.now();
    try {
      const txId = await doWithdraw(req.dept, amt, note, "دفعة مورد");
      let voucherId: number | null = null;
      try {
        const rv = await api.finance.paymentVouchers.create({ date: _localISO(), amount: amt, paid_to_type: "supplier", paid_to_id: req.supplierId ?? null, paid_to_name: req.supplier || "مورد", reason: note, dept: req.dept, category: "دفعة مورد", notes: note, drawer_tx_id: txId || null, settlement_breakdown: { purchaseRequest: { requestId: id, amount: amt } } as SettlementBreakdown });
        if (rv && (rv as any).id) { voucherId = (rv as any).id; setPaymentVouchersGlobal(p => [{ ...(rv as any), amount: Number((rv as any).amount) }, ...p]); }
      } catch { /* نكمل حتى لو فشل إنشاء سند الصرف */ }
      const r = await api.finance.purchaseRequests.payments.create(id, { amount: amt, note, drawer_tx_id: txId || null, payment_voucher_id: voucherId });
      if (!r || !(r as any).payment) throw new Error("payment save failed");
      const realId = (r as any).payment.id;
      // ── التحديث المحلي (تحديث "مبلغ الدفع" وإضافة السطر لسجل الدفعات) ما
      //    بيصير إلا بعد تأكد نجاح الحفظ الفعلي بالسيرفر، مش قبله ──
      setPurchaseRequests(p => p.map(x => x.id === id ? { ...x, paidAmount: (x.paidAmount || 0) + amt, payments: [...(x.payments || []), { id: realId, requestId: id, amount: amt, note, date: new Date().toISOString() }] } : x));
      return true;
    } catch {
      toast("⚠️ تعذّر حفظ الدفعة بالسيرفر — تحقق من الاتصال أو سجّل الدخول من جديد وحاول مرة أخرى", "error");
      return false;
    }
  };
  // ── تعديل تفاصيل جلسة (canEditSession) — يشمل بيانات الجلسة الأساسية والتشخيص
  //    والأدوية وإحالات المختبر/الأشعة. الأصناف الفرعية (تشخيص/أدوية/إحالات) لا
  //    تحمل معرّفات على الواجهة، لذا نتبع أسلوب "جلب ثم استبدال الكل": نجلب
  //    السجلات الحالية من قاعدة البيانات (ومعها معرّفاتها الحقيقية)، نحذفها كلها،
  //    ثم نعيد إنشاء القائمة الجديدة كاملة. ملاحظة مهمة: لا نلمس قائمة الديون
  //    المستقلة (debts) ولا حركات الدرج، لأن جدول الديون لا يحمل ربطاً مباشراً
  //    (sessionId) بالجلسة التي أنشأته، فلا توجد طريقة موثوقة لتحديد أي دين
  //    يقابل هذه الجلسة تحديداً — التعديل يقتصر على حقول الجلسة نفسها فقط ──
  const onEditSession = (id: number, updated: { doctor: string; date: string; notes: string; amount: number; paid: number; diagnoses: string[]; medications: { name: string; dose: string; freq: string; duration: string }[]; labRefs: string[]; radRefs: string[] }) => {
    const debt = Math.max(0, updated.amount - updated.paid);
    setSessions(prev => prev.map(s => s.id === id ? { ...s, doctor: updated.doctor, date: updated.date, notes: updated.notes, amount: updated.amount, paid: updated.paid, debt, diagnoses: updated.diagnoses, medications: updated.medications, labRefs: updated.labRefs, radRefs: updated.radRefs } : s));
    api.sessions.update(id, { doctor: updated.doctor, date: updated.date, notes: updated.notes, amount: updated.amount, paid: updated.paid, debt }).catch(() => { });
    // ── تشخيصات: جلب ثم استبدال الكل ──
    api.sessions.diagnoses.getAll(id).then((rows: any) => {
      const list = Array.isArray(rows) ? rows : [];
      Promise.all(list.map((r: any) => api.sessions.diagnoses.delete(id, r.id).catch(() => { }))).then(() => {
        updated.diagnoses.forEach(name => { api.sessions.diagnoses.create(id, { name }).catch(() => { }); });
      });
    }).catch(() => { });
    // ── أدوية: جلب ثم استبدال الكل ──
    api.sessions.medications.getAll(id).then((rows: any) => {
      const list = Array.isArray(rows) ? rows : [];
      Promise.all(list.map((r: any) => api.sessions.medications.delete(id, r.id).catch(() => { }))).then(() => {
        updated.medications.forEach(m => { api.sessions.medications.create(id, m).catch(() => { }); });
      });
    }).catch(() => { });
    // ── إحالات مختبر: جلب ثم استبدال الكل ──
    api.sessions.labRefs.getAll(id).then((rows: any) => {
      const list = Array.isArray(rows) ? rows : [];
      Promise.all(list.map((r: any) => api.sessions.labRefs.delete(id, r.id).catch(() => { }))).then(() => {
        updated.labRefs.forEach(name => { api.sessions.labRefs.create(id, { test_name: name }).catch(() => { }); });
      });
    }).catch(() => { });
    // ── إحالات أشعة: جلب ثم استبدال الكل ──
    api.sessions.radRefs.getAll(id).then((rows: any) => {
      const list = Array.isArray(rows) ? rows : [];
      Promise.all(list.map((r: any) => api.sessions.radRefs.delete(id, r.id).catch(() => { }))).then(() => {
        updated.radRefs.forEach(name => { api.sessions.radRefs.create(id, { image_name: name }).catch(() => { }); });
      });
    }).catch(() => { });
  };
  // ── تسديد دين المريض (من ملف المريض) كان يمسّ فقط سجل "الديون" (debts) —
  //    ضريبة إنشاء سند قبض + إيداع بالصندوق + تصفير/تخفيض صف الدين — لكنه لم
  //    يكن يمسّ أبداً حقل paid/debt على الجلسة (session) الأصلية التي نشأ منها
  //    الدين. النتيجة: "المدفوع" بملف المريض (يُحسب من مجموع session.paid) كان
  //    يبقى مجمَّداً عند قيمته وقت إنشاء الجلسة، حتى لو انسدَّد الدين بالكامل
  //    لاحقاً. لا يوجد ربط مباشر (session_id) على صف الدين، فنوزّع مبلغ السداد
  //    على جلسات المريض (بنفس القسم، أو كل الأقسام لو مدير) التي ما زال عليها
  //    دين، الأقدم فالأحدث — بنفس منطق التوزيع المستخدم أصلاً لتخفيض صفوف
  //    debts — لتبقى paid/debt على مستوى الجلسة متوافقة دائماً مع سجل الديون. ──
  // ── ترجع "خريطة توزيع" السداد بالضبط (أي جلسة أخدت قد إيش) — هذا ما كان
  //    موجوداً سابقاً، وهو السبب إنه حذف سند تسديد دين ما كان ممكن يرجّع
  //    أثره بدقة على الجلسات (انظر settlement_breakdown بالأسفل) ──
  const onSettleSessionsDebt = (patientId: string, deptId: string | null, amount: number): { sessionId: number; amount: number }[] => {
    const breakdown: { sessionId: number; amount: number }[] = [];
    setSessions(prev => {
      let rem = amount;
      // نمرّ بترتيب الأقدم أولاً (id تصاعدي) لتحديد المبلغ المطبَّق على كل جلسة،
      // ثم نطبّق النتيجة على المصفوفة الأصلية بنفس ترتيبها المعروض بالواجهة.
      const ordered = [...prev].sort((a, b) => a.id - b.id);
      const applyMap = new Map<number, { paid: number; debt: number }>();
      for (const s of ordered) {
        if (rem <= 0) break;
        if (s.patientId !== patientId || (deptId && s.dept !== deptId) || s.debt <= 0) continue;
        const apply = Math.min(s.debt, rem);
        rem -= apply;
        const paid = s.paid + apply;
        const debt = s.debt - apply;
        applyMap.set(s.id, { paid, debt });
        breakdown.push({ sessionId: s.id, amount: apply });
        api.sessions.update(s.id, { paid, debt }).catch(() => { });
      }
      return prev.map(s => applyMap.has(s.id) ? { ...s, ...applyMap.get(s.id)! } : s);
    });
    return breakdown;
  };
  // ── يعكس بدقة أثر سند تسديد دين محذوف: يرجّع لكل جلسة القيمة يلي كانت
  //    امتصتها من مبلغ السداد (المدفوع ينقص، الدين يزيد)، ويرجّع أي صف دين
  //    (debts) انحذف بالكامل وقتها أو نقص مبلغه — بدل ما يختفي الدين نهائياً
  //    من النظام لمجرد حذف سند القبض يلي وثّقه ──
  const reverseSettlementBreakdown = (breakdown: SettlementBreakdown) => {
    if (breakdown.sessions?.length) {
      setSessions(prev => {
        const applyMap = new Map<number, { paid: number; debt: number }>();
        prev.forEach(s => {
          const item = breakdown.sessions!.find(b => b.sessionId === s.id);
          if (!item) return;
          const paid = Math.max(0, s.paid - item.amount);
          const debt = s.debt + item.amount;
          applyMap.set(s.id, { paid, debt });
          api.sessions.update(s.id, { paid, debt }).catch(() => { });
        });
        return prev.map(s => applyMap.has(s.id) ? { ...s, ...applyMap.get(s.id)! } : s);
      });
    }
    if (breakdown.debts?.length) {
      setDebts(prev => {
        let next = [...prev];
        breakdown.debts!.forEach(item => {
          const idx = next.findIndex(d => d.id === item.debtId);
          if (idx >= 0) {
            const nd = { ...next[idx], amount: next[idx].amount + item.amount };
            next[idx] = nd;
            api.finance.debts.update(item.debtId, { amount: nd.amount }).catch(() => { });
          } else {
            // الصف انحذف بالكامل وقت السداد — نعيد إنشاءه بنفس بيانات المريض/القسم الأصلية
            const nd: DebtRow = { id: Date.now() + Math.floor(Math.random() * 1000), patient: item.snapshot.patient, pid: item.snapshot.pid, dept: item.snapshot.dept, amount: item.amount, date: item.snapshot.date, days: item.snapshot.days, phone: item.snapshot.phone };
            next = [nd, ...next];
            api.finance.debts.create({ patient: item.snapshot.patient, patient_id: item.snapshot.pid, dept: item.snapshot.dept, amount: item.amount, date: api.parseDateISO(item.snapshot.date), phone: item.snapshot.phone }).then(r => { if (r && (r as any).id) setDebts(p => p.map(d => d.id === nd.id ? { ...d, id: (r as any).id } : d)); }).catch(() => { });
          }
        });
        return next;
      });
    }
    if (breakdown.invoice) {
      const { invoiceId, amount } = breakdown.invoice;
      setInvoices(prev => prev.map(inv => {
        if (inv.id !== invoiceId) return inv;
        const paid = Math.max(0, inv.paid - amount);
        const remaining = inv.total - paid;
        const status: Invoice["status"] = remaining <= 0 ? "paid" : (paid > 0 ? "partial" : "unpaid");
        api.finance.invoices.update(invoiceId, { paid, status }).catch(() => { });
        return { ...inv, paid, remaining: Math.max(0, remaining), status };
      }));
    }
    if (breakdown.purchaseRequest) {
      const { requestId, amount } = breakdown.purchaseRequest;
      setPurchaseRequests(prev => prev.map(r => {
        if (r.id !== requestId) return r;
        const paidAmount = Math.max(0, (r.paidAmount || 0) - amount);
        api.finance.purchaseRequests.update(requestId, { paid_amount: paidAmount }).catch(() => { });
        return { ...r, paidAmount };
      }));
    }
  };
